rightX-30,choiceH=(panel.height-142-22)/3f;if(DrawOverlayChoice(new Rect(rightX,panel.y+102,rightW,choiceH),"代償を支払う","HP -6　／　24Gを獲得",new Color(.58f,.17f,.18f))){run.hp=Mathf.Max(1,run.hp-6);run.gold+=24;CloseMapEvent("代償を払い、24Gを得た");}if(DrawOverlayChoice(new Rect(rightX,panel.y+102+choiceH+11,rightW,choiceH),"残響を修復する","すべての装備の耐久を回復",new Color(.18f,.45f,.36f))){foreach(var item in run.inventory)item.durability=6;CloseMapEvent("残響が装備を修復した");}if(DrawOverlayChoice(new Rect(rightX,panel.y+102+(choiceH+11)*2,rightW,choiceH),"靄を振り払う","何も得ず、地図の探索へ戻る",new Color(.42f,.34f,.24f)))CloseMapEvent("黒い靄を振り払い、探索へ戻った");}
