  Color inkColor=new(.20f,.105f,.045f),muted=new(.38f,.24f,.12f);Rect headerRect=new(Screen.width*.09f,Screen.height*.025f,Screen.width*.82f,Screen.height*.145f);GUI.Box(headerRect,GUIContent.none,new GUIStyle(){normal={background=bookChipTex},border=new RectOffset(14,14,14,14)});
