  if(mapEventOverlay||mapLoadoutOverlay)return;bool transition=map.current==map.exit&&map.currentZone<map.zones.Count-1&&DungeonSystem.ExitUnlocked(map);if(transition){DrawMapTransitionButtons(action);return;}
  Rect backRect=new(action.x+Us(22),action.yMax-Us(58),Us(162),Us(48)),packRect=new(action.x+Us(196),action.yMax-Us(58),Us(178),Us(48)),lootRect=new(action.x+Us(386),action.yMax-Us(58),Us(154),Us(48)),moveRect=new(action.xMax-Us(258),action.yMax-Us(62),Us(236),Us(52));GUI.enabled=map.currentZone==0&&map.current==map.entrance;if(GUI.Button(backRect,"遠征を終了",button)){GUI.enabled=true;FinishRun(true);return;}GUI.enabled=true;if(GUI.Button(packRect,"編成カード確認",button)){mapLoadoutTab=0;mapLoadoutOverlay=true;}if(GUI.Button(lootRect,$"戦利品 {run.lootBag.Count}",button)){mapLoadoutTab=1;mapLoadoutOverlay=true;}bool canMove=selected.id!=map.current&&DungeonSystem.Connected(map,map.current,selected.id)&&DungeonSystem.CanMove(map,selected.id);GUI.enabled=canMove;if(GUI.Button(moveRect,canMove?"この地点へ移動":"移動先を選択",new GUIStyle(button){fontSize=Fs(19),fontStyle=FontStyle.Bold})){GUI.enabled=true;if(DungeonSystem.Move(map,selected.id,run)){selectedMapNodeId=map.current;EnterNode(selected);}return;}GUI.enabled=true;
