 void DrawMapCompass(Rect rect){GUI.color=new Color(.18f,.10f,.045f,.88f);GUI.DrawTexture(rect,mapNodeCircleTex,ScaleMode.StretchToFill,true);GUI.color=Color.white;DrawCircleRing(rect,new Color(.76f,.55f,.25f,.92f),3);DrawCircleRing(new Rect(rect.x+Us(8),rect.y+Us(8),rect.width-Us(16),rect.height-Us(16)),new Color(.34f,.20f,.09f,.85f),2);GUI.Label(new Rect(rect.x,rect.y+Us(5),rect.width,Us(25)),"探索方位盤",new GUIStyle(header){fontSize=Fs(14),fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleCenter,normal={textColor=new Color(.91f,.75f,.42f)}});DrawAxisTriangle(new Rect(rect.x+Us(12),rect.y+Us(28),rect.width-Us(24),rect.height-Us(35)));}
