 string NodeEffectPreview(MapNode node){int collapse=node.type=="treasure"?2:node.type=="rest"?-1:0,corruption=node.type=="event"?2:node.type=="battle"?1:0;return $"警戒 +1　崩壊 {collapse:+#;-#;±0}　侵蝕 {corruption:+#;-#;±0}";}
 void DrawMapTransitionButtons(Rect action){GUI.Label(new Rect(action.center.x-130,action.y+8,260,28),"区域踏破 ― 次の行動",new GUIStyle(header){fontSize=20,alignment=TextAnchor.MiddleCenter});float w=(action.width-64)/3f,y=action.yMax-59;if(GUI.Button(new Rect(action.x+16,y,w,48),"野営して進む",button)){run.hp=Mathf.Min(run.maxHp,run.hp+8);foreach(var item in run.inventory)item.durability=Mathf.Min(6,item.durability+1);AdvanceZone();selectedMapNodeId=map.current;}if(GUI.Button(new Rect(action.x+24+w,y,w,48),"痕跡を消して進む",button)){run.axes.Change(-2,0,1);AdvanceZone();selectedMapNodeId=map.current;}if(GUI.Button(new Rect(action.x+32+w*2,y,w,48),"残骸を回収して進む",button)){run.gold+=18;run.axes.Change(0,2,0);AdvanceZone();selectedMapNodeId=map.current;}}
 Vector2 MapPoint(Rect area,MapNode node)=>new(area.x+area.width*node.x/100f,area.y+area.height*node.y/100f);
 void DrawMapTerrain(Rect area){if(mapTerrain!=null)GUI.DrawTexture(area,mapTerrain,ScaleMode.ScaleAndCrop,true);else DrawDungeonArt(area,run.dungeon);GUI.color=new Color(1f,.91f,.72f,.15f);GUI.DrawTexture(area,Texture2D.whiteTexture);GUI.color=Color.white;}
 void DrawMapRoadV2(Vector2 start,Vector2 end,bool active){Vector2 delta=end-start;float length=delta.magnitude;if(length<1)return;DrawMapLineV2(start,end,active?new Color(.62f,.42f,.13f,.42f):new Color(.20f,.16f,.10f,.30f),8f);if(mapRoad!=null){Matrix4x4 old=GUI.matrix;GUIUtility.RotateAroundPivot(Mathf.Atan2(delta.y,delta.x)*Mathf.Rad2Deg,start);GUI.color=active?new Color(1f,.86f,.56f,.90f):new Color(.68f,.65f,.55f,.46f);GUI.DrawTextureWithTexCoords(new Rect(start.x,start.y-7f,length,14f),mapRoad,new Rect(0,0,Mathf.Max(1,length/150f),1),true);GUI.color=Color.white;GUI.matrix=old;}else DrawMapLineV2(start,end,new Color(.42f,.36f,.24f,.72f),6f);if(active)DrawMapLineV2(start,end,new Color(1f,.72f,.24f,.62f),2f);}
 void DrawMapLineV2(Vector2 start,Vector2 end,Color color,float width){Vector2 delta=end-start;float length=delta.magnitude;if(length<1)return;Matrix4x4 old=GUI.matrix;GUIUtility.RotateAroundPivot(Mathf.Atan2(delta.y,delta.x)*Mathf.Rad2Deg,start);GUI.color=color;GUI.DrawTexture(new Rect(start.x,start.y-width*.5f,length,width),Texture2D.whiteTexture);GUI.color=Color.white;GUI.matrix=old;}
