 void DrawAxisTriangle(Rect rect){Vector2 center=new(rect.center.x,rect.center.y+Us(5)),top=new(rect.center.x,rect.y+Us(15)),left=new(rect.x+Us(30),rect.yMax-Us(22)),right=new(rect.xMax-Us(30),rect.yMax-Us(22));Color grid=new(.34f,.23f,.13f,.46f);for(int i=1;i<=3;i++){float t=i/3f;Vector2 a=Vector2.Lerp(center,top,t),b=Vector2.Lerp(center,right,t),c=Vector2.Lerp(center,left,t);DrawMapLineV2(a,b,grid,1.5f);DrawMapLineV2(b,c,grid,1.5f);DrawMapLineV2(c,a,grid,1.5f);}DrawMapLineV2(center,top,grid,1.5f);DrawMapLineV2(center,left,grid,1.5f);DrawMapLineV2(center,right,grid,1.5f);Vector2 pAlert=Vector2.Lerp(center,top,Mathf.InverseLerp(-15,15,run.axes.alert)),pCollapse=Vector2.Lerp(center,right,Mathf.InverseLerp(-15,15,run.axes.collapse)),pCorruption=Vector2.Lerp(center,left,Mathf.InverseLerp(-15,15,run.axes.corruption));DrawMapLineV2(pAlert,pCollapse,new Color(.72f,.26f,.16f,.92f),Us(4));DrawMapLineV2(pCollapse,pCorruption,new Color(.62f,.35f,.16f,.92f),Us(4));DrawMapLineV2(pCorruption,pAlert,new Color(.47f,.23f,.56f,.92f),Us(4));DrawAxisPoint(pAlert,new Color(.72f,.22f,.15f));DrawAxisPoint(pCollapse,new Color(.68f,.43f,.12f));DrawAxisPoint(pCorruption,new Color(.44f,.20f,.58f));var labelStyle=new GUIStyle(body){fontSize=Fs(13),fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleCenter,clipping=TextClipping.Overflow,normal={textColor=new Color(.24f,.13f,.06f)}};GUI.Label(new Rect(top.x-Us(56),rect.y-Us(1),Us(112),Us(24)),$"警戒 {run.axes.alert:+#;-#;0}",labelStyle);GUI.Label(new Rect(right.x-Us(24),right.y-Us(2),Us(105),Us(24)),$"崩壊 {run.axes.collapse:+#;-#;0}",labelStyle);GUI.Label(new Rect(left.x-Us(82),left.y-Us(2),Us(105),Us(24)),$"侵蝕 {run.axes.corruption:+#;-#;0}",labelStyle);}
 void DrawAxisPoint(Vector2 point,Color color){Rect r=new(point.x-Us(5),point.y-Us(5),Us(10),Us(10));GUI.color=color;GUI.DrawTexture(r,mapNodeCircleTex);GUI.color=Color.white;}
