 void DrawMapPlayerToken(Rect rect){GUI.color=new Color(0,0,0,.42f);GUI.DrawTexture(new Rect(rect.x+Us(4),rect.y+Us(5),rect.width,rect.height),mapNodeCircleTex,ScaleMode.StretchToFill,true);GUI.color=Color.white;GUI.BeginGroup(rect);DrawCharacter(new Rect(-rect.width*.10f,-rect.height*.02f,rect.width*1.20f,rect.height*1.20f),meta.body,meta.hair);GUI.EndGroup();}
 void DrawMapLoadoutOverlay(){Rect full=new(0,0,Screen.width,Screen.height);GUI.color=new Color(.008f,.009f,.008f,.78f);GUI.DrawTexture(full,Texture2D.whiteTexture);GUI.color=Color.white;Rect panel=new(Screen.width*.11f,Screen.height*.075f,Screen.width*.78f,Screen.height*.84f);GUI.DrawTexture(panel,backpackLeatherTex,ScaleMode.StretchToFill,true);Rect page=new(panel.x+Us(22),panel.y+Us(20),panel.width-Us(44),panel.height-Us(40));GUI.Box(page,GUIContent.none,new GUIStyle(){normal={background=bookChipTex},border=new RectOffset(14,14,14,14)});GUI.Label(new Rect(page.x+Us(24),page.y+Us(12),page.width-Us(48),Us(38)),"遠征記録 ― 持ち込み品",new GUIStyle(screenTitle){fontSize=Fs(26),fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleLeft,normal={textColor=new Color(.23f,.12f,.05f)}});float tabW=Us(190);if(GUI.Button(new Rect(page.x+Us(24),page.y+Us(58),tabW,Us(48)),"編成・カード",mapLoadoutTab==0?navSelected:navButton))mapLoadoutTab=0;if(GUI.Button(new Rect(page.x+Us(24)+tabW+Us(10),page.y+Us(58),tabW,Us(48)),$"戦利品 {run.lootBag.Count}",mapLoadoutTab==1?navSelected:navButton))mapLoadoutTab=1;if(GUI.Button(new Rect(page.xMax-Us(148),page.y+Us(16),Us(124),Us(44)),"地図へ戻る",button))mapLoadoutOverlay=false;Rect content=new(page.x+Us(24),page.y+Us(120),page.width-Us(48),page.height-Us(144));if(mapLoadoutTab==0)DrawReadonlyLoadout(content);else DrawReadonlyLoot(content);}
 void DrawReadonlyLoadout(Rect area){var build=BackpackSystem.Build(run);string bag=GameCatalog.Backpacks.FirstOrDefault(x=>x.id==run.backpack)?.name??run.backpack;GUI.Label(new Rect(area.x,area.y,area.width,Us(30)),$"{bag}　／　配置装備 {run.placements.Count}　／　デッキ {build.deck.Count}枚",new GUIStyle(header){fontSize=Fs(19),clipping=TextClipping.Overflow,normal={textColor=new Color(.28f,.15f,.06f)}});float itemSize=Us(82);for(int i=0;i<run.inventory.Count&&i<8;i++){Rect r=new(area.x+i*(itemSize+Us(8)),area.y+Us(42),itemSize,itemSize);DrawItemArt(r,run.inventory[i].templateId);DrawOutline(r,new Color(.48f,.31f,.13f),2);}float cardW=(area.width-Us(45))/4f,cardH=Mathf.Min(Us(178),area.height-Us(155));for(int i=0;i<build.deck.Count&&i<8;i++){int row=i/4,col=i%4;Rect cardRect=new(area.x+col*(cardW+Us(15)),area.y+Us(142)+row*(cardH+Us(12)),cardW,cardH);DrawReadonlyCard(cardRect,build.deck[i]);}}
 void DrawReadonlyCard(Rect rect,CardInstance cardData){GUI.Box(rect,GUIContent.none,bookEntryStyle);Color accent=cardData.type==CardType.Attack?new Color(.62f,.22f,.15f):cardData.type==CardType.Skill?new Color(.16f,.39f,.52f):new Color(.42f,.24f,.52f);GUI.color=accent;GUI.DrawTexture(new Rect(rect.x,rect.y,Us(7),rect.height),Texture2D.whiteTexture);GUI.color=Color.white;GUI.Label(new Rect(rect.x+Us(13),rect.y+Us(8),Us(38),Us(34)),cardData.cost.ToString(),new GUIStyle(header){fontSize=Fs(23),alignment=TextAnchor.MiddleCenter,normal={textColor=accent}});GUI.Label(new Rect(rect.x+Us(54),rect.y+Us(8),rect.width-Us(65),Us(34)),cardData.name,new GUIStyle(header){fontSize=Fs(17),fontStyle=FontStyle.Bold,clipping=TextClipping.Overflow,normal={textColor=new Color(.26f,.14f,.06f)}});GUI.Label(new Rect(rect.x+Us(15),rect.y+Us(50),rect.width-Us(30),rect.height-Us(72)),cardData.text,new GUIStyle(body){fontSize=Fs(14),wordWrap=true,clipping=TextClipping.Overflow,normal={textColor=new Color(.34f,.23f,.14f)}});GUI.Label(new Rect(rect.x+Us(14),rect.yMax-Us(25),rect.width-Us(28),Us(20)),cardData.source,new GUIStyle(screenSubtitle){fontSize=Fs(11),alignment=TextAnchor.MiddleRight,clipping=TextClipping.Overflow,normal={textColor=new Color(.44f,.31f,.20f)}});}
 void DrawReadonlyLoot(Rect area){GUI.Label(new Rect(area.x,area.y,area.width,Us(34)),"この遠征で獲得した戦利品",new GUIStyle(header){fontSize=Fs(20),normal={textColor=new Color(.28f,.15f,.06f)}});if(run.lootBag.Count==0){GUI.Label(new Rect(area.x,area.y+Us(80),area.width,Us(90)),"まだ戦利品はありません\n戦闘報酬や宝物区画で獲得した品がここへ記録されます。",new GUIStyle(body){fontSize=Fs(18),fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleCenter,wordWrap=true,normal={textColor=new Color(.42f,.31f,.20f)}});return;}float size=Mathf.Min(Us(150),(area.width-Us(64))/5f);for(int i=0;i<run.lootBag.Count;i++){int row=i/5,col=i%5;var item=run.lootBag[i];Rect r=new(area.x+col*(size+Us(16)),area.y+Us(48)+row*(size+Us(48)),size,size);DrawItemArt(r,item.templateId);DrawOutline(r,TypeColor(GameCatalog.Items[item.templateId].type),3);GUI.Label(new Rect(r.x-Us(5),r.yMax+Us(5),r.width+Us(10),Us(36)),item.identified?GameCatalog.Items[item.templateId].name:"未鑑定品",new GUIStyle(body){fontSize=Fs(15),fontStyle=FontStyle.Bold,alignment=TextAnchor.UpperCenter,wordWrap=true,clipping=TextClipping.Overflow,normal={textColor=new Color(.29f,.17f,.08f)}});}}
 Color TypeColor(ItemType t)=>t==ItemType.Weapon?new(.54f,.21f,.16f):t==ItemType.Armor?new(.16f,.38f,.48f):t==ItemType.Rune?new(.39f,.22f,.51f):new(.56f,.42f,.14f);
}
}
